function HttpIcon({ className }: IconProps) {
  return (
    <Globe
      className={className ?? SIZE}
      strokeWidth={1.5}
    />
  );
}

const ICON_MAP: Record<string, (props: IconProps) => React.ReactElement> = {
  OpenAI: OpenAIIcon,
  Anthropic: AnthropicIcon,
  Slack: SlackIcon,
  Postgres: PostgresIcon,
  Notion: NotionIcon,
  GitHub: GitHubBrandIcon,
  Linear: LinearIcon,
  Stripe: StripeIcon,
  HubSpot: HubspotIcon,
  Sendgrid: SendgridIcon,
  AWS: AwsIcon,
  HTTP: HttpIcon,
};

export function IntegrationIcon({
  name,
  className,
}: {
  name: string;
  className?: string;
}) {
  const Icon = ICON_MAP[name];
  if (!Icon) {
    return (
      <span
        className={`inline-block rounded-md bg-accent border border-border ${className ?? SIZE}`}
        aria-hidden
      />
    );
  }
  return <Icon className={className} />;
}
